sql:
SELECT contact_email
FROM leas
WHERE total_budget = (SELECT MAX(total_budget) FROM leas);

SELECT lea_id, metric_value
FROM lea_metrics
WHERE metric_name = 'average A-level pass rate';

SELECT population_size
FROM leas
ORDER BY population_size DESC;

SELECT lea_id, lea_name
FROM leas
ORDER BY lea_name ASC;

SELECT instructor_name
FROM instructors
WHERE years_of_experience = (SELECT MIN(years_of_experience) FROM instructors);

SELECT school_count
FROM lea_schools
WHERE lea_id = 1;

SELECT AVG(assignment_count) AS average_instructors_per_school
FROM (
    SELECT school_id, COUNT(instructor_id) AS assignment_count
    FROM school_instructor_assignments
    GROUP BY school_id
) AS instructor_count_per_school;

SELECT lea_name
FROM leas
ORDER BY lea_name;

SELECT lea_name 
FROM leas 
WHERE lea_id = 1;

SELECT lea_id, metric_name, metric_value
FROM lea_performance
WHERE lea_id = 1 AND metric_name = '1';
